queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?platform_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:platform_id ?cg . ?child a :Platforms ; p:id ?cg . ?l p:content_creator_id ?pg . ?parent a :Content_Creators ; p:id ?pg . } GROUP BY ?child }
  ?child p:platform_name ?platform_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Content_Creators } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?platform_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:platform_id ?cg . ?child a :Platforms ; p:id ?cg . ?l p:content_creator_id ?pg . ?parent a :Content_Creators ; p:id ?pg . } GROUP BY ?child }
  ?child p:platform_name ?platform_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Content_Creators } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?platform_name WHERE {
  ?content_creators_platforms a :Content_Creators_Platforms .
  ?platforms a :Platforms .
  ?content_creators_platforms p:hasPlatforms ?platforms .
  ?content_creators a :Content_Creators .
  ?content_creators_platforms p:hasContent_Creators ?content_creators .
  ?content_creators p:name ?name .
  ?platforms p:platform_name ?platform_name .
} }
}
